values
('additional-maths:10-2-solving-equations-numerically:match:cd02f0b1', 'additional-maths', 'additional-maths:10-2-solving-equations-numerically', '10.2 Solving Equations Numerically', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Iteration diverges”?", "options": ["Change of sign, so a root lies in \\( [2,\\ 3] \\)", "A root lies between \\( a \\) and \\( b \\)", "At least 4 significant figures", "The rearrangement is unsuitable — the values run away"]}'::jsonb, '{"answer": 3, "explain": "“Iteration diverges” means: The rearrangement is unsuitable — the values run away"}'::jsonb),
('additional-maths:10-2-solving-equations-numerically:match:5e0c60dc', 'additional-maths', 'additional-maths:10-2-solving-equations-numerically', '10.2 Solving Equations Numerically', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Two roots inside one search step”?", "options": ["The rearrangement is unsuitable — the values run away", "No sign change is seen, so the search misses them", "You must write the conclusion sentence", "A root lies between \\( a \\) and \\( b \\)"]}'::jsonb, '{"answer": 1, "explain": "“Two roots inside one search step” means: No sign change is seen, so the search misses them"}'::jsonb),
('additional-maths:10-2-solving-equations-numerically:match:559915d8', 'additional-maths', 'additional-maths:10-2-solving-equations-numerically', '10.2 Solving Equations Numerically', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Repeated (double) root”?", "options": ["The curve touches the axis: no sign change", "No sign change is seen, so the search misses them", "A root lies between \\( a \\) and \\( b \\)", "Feeds the previous output back in as the next input"]}'::jsonb, '{"answer": 0, "explain": "“Repeated (double) root” means: The curve touches the axis: no sign change"}'::jsonb),
('additional-maths:10-2-solving-equations-numerically:match:c4e749aa', 'additional-maths', 'additional-maths:10-2-solving-equations-numerically', '10.2 Solving Equations Numerically', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( \\text{f}(0.75) > 0,\\ \\text{f}(0.8) < 0 \\)”?", "options": ["Feeds the previous output back in as the next input", "The curve touches the axis: no sign change", "Root lies in \\( [0.75,\\ 0.8] \\), so \\( 0.8 \\) to 1 dp", "No sign change is seen, so the search misses them"]}'::jsonb, '{"answer": 2, "explain": "“\\( \\text{f}(0.75) > 0,\\ \\text{f}(0.8) < 0 \\)” means: Root lies in \\( [0.75,\\ 0.8] \\), so \\( 0.8 \\) to 1 dp"}'::jsonb),
('additional-maths:10-2-solving-equations-numerically:match:d7db0a1f', 'additional-maths', 'additional-maths:10-2-solving-equations-numerically', '10.2 Solving Equations Numerically', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “''Show that a root lies between…''”?", "options": ["The rearrangement is unsuitable — the values run away", "Root lies in \\( [0.75,\\ 0.8] \\), so \\( 0.8 \\) to 1 dp", "No sign change is seen, so the search misses them", "You must write the conclusion sentence"]}'::jsonb, '{"answer": 3, "explain": "“''Show that a root lies between…''” means: You must write the conclusion sentence"}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:0fb73b51', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "A question asks for the ''exact'' solution of an equation. Which answer can score full marks?", "options": ["\\( -1 + \\sqrt{7} \\)", "\\( 1.646 \\)", "\\( 1.65 \\)", "about \\( 1.6 \\)"]}'::jsonb, '{"answer": 0, "explain": "''Exact'' requires surd/fraction/π form; only the surd \\( -1 + \\sqrt{7} \\) qualifies. A decimal alone scores 0."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:e74c65ae', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "A ''show that'' question prints the result to reach. How do you secure all the marks?", "options": ["Show every step and add a concluding statement", "Write the given answer in a box", "Give a decimal to 3 s.f.", "State the answer with no working"]}'::jsonb, '{"answer": 0, "explain": "The result is given (AG), so marks are for full valid working plus the concluding sentence."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:6fb383ad', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "On a question worth 2 marks for the ''exact'' roots, a student writes only \\( x = 1.24 \\) and \\( x = -3.24 \\). The mark is:", "options": ["0 — decimals are not exact", "2 — the values are right", "1 — half credit", "1 — for one root"]}'::jsonb, '{"answer": 0, "explain": "Decimal-only answers to an exact question receive no marks (2024 examiner report, Q3(b))."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:350a35ad', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "''In this question you must show detailed reasoning.'' A correct factorisation is written with no method. The mark is:", "options": ["0 — the reasoning must be shown", "Full — the factors are correct", "Half marks", "1 mark"]}'::jsonb, '{"answer": 0, "explain": "DR requires the full analytical method; an answer-only solution scores 0 even when correct (2024 Q8(a))."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:dfca5a7a', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "Part (b) begins ''Hence solve...''. This instructs you to:", "options": ["Use the result from the previous part", "Start a completely new method", "Give the answer as a decimal", "Use the calculator''s equation solver"]}'::jsonb, '{"answer": 0, "explain": "''Hence'' means build on the previous result; a fresh method risks losing marks and time."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:e5d7a5cb', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "''Write down the coordinates of the y-intercept.'' What is expected?", "options": ["Just the coordinate pair, with no working", "A full algebraic method", "An exact surd", "A sketch of the curve"]}'::jsonb, '{"answer": 0, "explain": "''Write down'' asks only for the result; no method is required."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:53f12189', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "Which pair of command words differ mainly in whether justification must be shown?", "options": ["''State'' (answer only) vs ''Determine'' (answer with justification)", "''Plot'' vs ''Sketch''", "''Exact'' vs ''Give''", "''Hence'' vs ''Show that''"]}'::jsonb, '{"answer": 0, "explain": "''State/write down'' want only the result; ''determine/find'' want the result supported by visible reasoning."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:2efd2e91', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "A question says ''Sketch the graph of \\( y = 2^x \\)''. You should:", "options": ["Show shape, the y-intercept and the asymptote — not to scale", "Plot exact points on a grid", "Give a table of 10 values", "Solve \\( 2^x = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "''Sketch'' means main features only; ''plot'' would require accurate points on a grid."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:8a959b27', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "A stationary point is found at \\( x = 3 \\). What is the fully-credited answer?", "options": ["The pair \\( (3,\\ y) \\) with the \\( y \\)-value worked out", "\\( x = 3 \\) only", "\\( y = 3 \\)", "\\( 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "Coordinates must be given as pairs; an x-value alone loses the mark (2024 Q10)."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:b90a6bc7', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "A student earns no method mark but writes the correct final value. Under OCR rules:", "options": ["No accuracy mark is possible — ''M0 A1 cannot be awarded''", "The accuracy mark is still given", "Both marks are awarded", "A bonus mark applies"]}'::jsonb, '{"answer": 0, "explain": "Accuracy marks depend on the method mark, so M0 A1 can never be awarded — unless the scheme states ''answer only scores full''."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:1712be2f', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "The scheme writes ''cao'' next to an answer. This means:", "options": ["Correct answer only — no follow-through or alternatives", "Calculator answer okay", "Correct, and other forms accepted", "Complete all options"]}'::jsonb, '{"answer": 0, "explain": "''cao'' = correct answer only; equivalent or follow-through forms are not credited there."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:mcq:c6ec5547', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'mcq', 'mcq', 1, '{"question": "The scheme writes ''oe'' after an equation such as \\( 3y = 2x + 12 \\). This means:", "options": ["Any algebraically equivalent form is accepted", "Only that exact form is accepted", "Decimal answers only", "Omit the equals sign"]}'::jsonb, '{"answer": 0, "explain": "''oe'' = or equivalent, so \\( y = \\tfrac{2}{3}x + 4 \\) would also score."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:c836c5c1', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "On a question that asks for the ''exact'' value, giving only a decimal such as 1.41 scores full marks."}'::jsonb, '{"answer": false, "explain": "''Exact'' requires surd/fraction/π form; a decimal alone scores 0. Give the exact form (optionally with the decimal)."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:660cefeb', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "For a ''show that'' question the result is already printed, so all the marks are for showing valid working and a concluding statement."}'::jsonb, '{"answer": true, "explain": "The answer is given (AG); the credit is entirely for the journey and the concluding sentence."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:c3fcf1dc', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "''Write down'' questions expect you to show your full method."}'::jsonb, '{"answer": false, "explain": "''Write down'' / ''state'' / ''give'' want only the result; no working is required."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:202f6847', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "If a question says ''In this question you must show detailed reasoning'', solving it on a calculator scores 0 even if the answer is correct."}'::jsonb, '{"answer": true, "explain": "DR requires the full analytical method; a calculator-only answer scores nothing."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:70839c92', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "The command word ''Hence'' means you may ignore the previous part and start again."}'::jsonb, '{"answer": false, "explain": "''Hence'' means you must use the previous result; starting a new method risks losing marks."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:29513735', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "''M0 A1'' can never be awarded, because an accuracy mark needs its method mark."}'::jsonb, '{"answer": true, "explain": "A marks are conditional on the associated M mark being earned."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:510dbd4a', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "''Sketch'' means you must plot points accurately on a grid."}'::jsonb, '{"answer": false, "explain": "''Sketch'' shows main features only; it is ''plot'' that requires accurate points on a grid."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tf:977c2815', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tf', 'tf', 1, '{"question": "''ft'' (follow-through) lets you earn later marks after an earlier mistake, provided there is no further error."}'::jsonb, '{"answer": true, "explain": "Follow-through credits correct subsequent work built on an earlier wrong value, if no new error is made."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:learn:cfcfa55e', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'learn', 'mcq', 1, '{"readingTitle": "Why does the command word decide your marks?", "reading": "<p>Every 6993 question begins with an <strong>instruction verb</strong> — the <strong>command word</strong>. It is a <em>contract</em>: it tells you exactly what the examiner will reward and, just as importantly, what will score <strong>nothing</strong> however good your maths is.</p>\n            <ul>\n              <li>The command word decides <strong>how much you must write</strong>: \"write down\" wants only the answer, while \"show that\" and \"detailed reasoning\" want every step.</li>\n              <li>It decides the <strong>form of the answer</strong>: \"exact\" forbids a decimal, and a coordinate answer must be a <strong>pair</strong>.</li>\n              <li>Getting the right number is not enough — a correct answer in the wrong form, or with no working where working is demanded, is a common way even this top set still loses marks.</li>\n              <li>Examiners report the same command-word slips every year. Reading the verb first, and answering it literally, is one of the cheapest ways to raise your grade.</li>\n            </ul>\n            <p>This page is a checklist for the whole paper: learn the contract once and it pays off on every question.</p>", "question": "What is a ''command word''?", "options": ["The instruction verb that says what the answer must contain", "The hardest word in the question", "The topic of the question", "The number of marks"]}'::jsonb, '{"answer": 0, "explain": "The command word (exact, show that, determine, hence…) is a contract for what will and will not be rewarded."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:learn:968427d8', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'learn', 'mcq', 1, '{"readingTitle": "What does each OCR command word demand?", "reading": "<p>OCR uses a fixed set of command words. Learn what each one <em>requires</em>:</p>\n            <table class=\"worked\">\n              <tr><td><strong>Exact</strong></td><td>Leave the answer in surd, fraction or π form. A decimal alone scores 0.</td></tr>\n              <tr><td><strong>Show that</strong></td><td>The result is printed for you. Show every step <em>and</em> write a concluding statement.</td></tr>\n              <tr><td><strong>Determine</strong> / <strong>Find</strong></td><td>Reach the result with <em>visible justification</em>, not just a bare value.</td></tr>\n              <tr><td><strong>Give</strong> / <strong>State</strong> / <strong>Write down</strong></td><td>Quote the result; no working or method is expected.</td></tr>\n              <tr><td><strong>Hence</strong></td><td>Use the result you have just found; do not start a new method.</td></tr>\n            </table>\n            <p>So \"<strong>state</strong> the gradient\" and \"<strong>determine</strong> the gradient\" are different tasks: the first wants a number, the second wants the number <em>with</em> the reasoning that produced it.</p>\n            <p>For an \"exact\" answer, write, e.g., \\( x = -3 + 2\\sqrt{5} \\) rather than \\( 1.47 \\). If you like, give <em>both</em> — the exact form earns the marks and the decimal cannot lose them.</p>", "question": "A question says ''Write down the value of f(0)''. What is expected?", "options": ["Just the answer, with no working", "A full method with every step", "An exact surd", "A graph"]}'::jsonb, '{"answer": 0, "explain": "''Write down'' / ''state'' / ''give'' ask only for the result; no method is required."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:learn:c5e5092f', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'learn', 'mcq', 1, '{"readingTitle": "What does ''show that'' require that an ordinary solve does not?", "reading": "<p>In a <strong>show that</strong> question the answer is <em>given</em> to you (the mark scheme labels it <strong>AG</strong> — \"answer given\"). Every mark is therefore for the <strong>journey</strong>, not the destination.</p>\n            <ul>\n              <li>Write a <strong>full chain of working</strong> that clearly reaches the printed result — you cannot \"accidentally\" earn marks by quoting the answer.</li>\n              <li>Finish with an explicit <strong>concluding statement</strong>. This is the mark most often lost.</li>\n              <li>Change-of-sign example: after computing \\( \\text{f}(2) \\) and \\( \\text{f}(3) \\), add the sentence \"there is a change of sign, so there is a root between \\( x = 2 \\) and \\( x = 3 \\)\".</li>\n              <li>For \"show these lines are perpendicular\", state both gradients, show their product is \\( -1 \\), and write the word <strong>perpendicular</strong>.</li>\n            </ul>\n            <p>A calculation that stops at the numbers, with no concluding sentence, typically earns the method mark but loses the final accuracy mark.</p>", "question": "In a ''show that'' change-of-sign question, what is most often missing?", "options": ["The concluding sentence stating a root lies in the interval", "The value of f at each end", "A calculator", "The graph"]}'::jsonb, '{"answer": 0, "explain": "Candidates compute f at each end but omit the ''change of sign ⇒ root in interval'' statement, losing the final mark."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:learn:36425c75', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'learn', 'mcq', 1, '{"readingTitle": "What is a ''detailed reasoning'' question — and why can a right answer score 0?", "reading": "<p>When a question prints \"<strong>In this question you must show detailed reasoning</strong>\" (DR), you must present the <strong>full analytical method</strong>. Solving it on the calculator and writing only the answer scores <strong>0</strong> — even when the answer is correct.</p>\n            <ul>\n              <li>Example: a DR factor-theorem question needs you to show \\( \\text{f}(a) = 0 \\) for a trial value, obtain the quadratic factor, then state all three factors. An answer-only factorisation scored nothing in the 2024 report.</li>\n              <li>For an iteration, every iterate must be written to at least <strong>4 significant figures</strong> before you give the 3 s.f. conclusion.</li>\n              <li>The mark scheme spells out which lines \"must be seen\" — treat DR like show that with no shortcuts.</li>\n            </ul>\n            <p><strong>\"Hence\"</strong> is a related instruction: it tells you to <em>use the previous result</em>. If part (b) says \"hence solve\", start from what part (a) gave you — do not reach for a fresh method. Ignoring \"hence\" (e.g. calculator-solving instead of reading a graph you were told to use) loses marks and wastes time.</p>", "question": "A DR question is solved correctly on a calculator with no method shown. The mark is:", "options": ["0 — the method must be shown", "Full marks — the answer is right", "Half marks", "1 mark for the answer"]}'::jsonb, '{"answer": 0, "explain": "''Detailed reasoning'' requires the full analytical method; a calculator-only solution scores 0 even if correct."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:learn:68bda6a1', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'learn', 'mcq', 1, '{"readingTitle": "Plot, sketch or draw — and how should you use the calculator?", "reading": "<p>The three graph verbs are <em>not</em> interchangeable:</p>\n            <ul>\n              <li><strong>Plot</strong> — mark calculated points <em>accurately</em> on the printed grid and join them (a smooth curve or ruled line within half a square).</li>\n              <li><strong>Sketch</strong> — show the <strong>main features</strong> only (shape, intercepts, asymptotes, turning points); it need not be to scale.</li>\n              <li><strong>Draw</strong> — produce the graph or diagram to <strong>reasonable accuracy</strong>.</li>\n            </ul>\n            <p><strong>Calculator conduct</strong> (printed in the spec — a calculator is allowed throughout):</p>\n            <ul>\n              <li><strong>Write down any expression you evaluate</strong> on the calculator, e.g. show \\( \\sqrt{3^2 + 4^2} \\) before writing \\( 5 \\). If only the answer appears on a \"must show working\" question, the method marks are gone.</li>\n              <li>Use <strong>correct mathematical notation</strong>, not calculator notation — write \\( x^2 \\) and \\( \\frac{3}{4} \\), not the ambiguous strings a calculator screen shows.</li>\n              <li>A calculator answer never replaces the reasoning on a show-that or DR question.</li>\n            </ul>", "question": "Which command word requires accurate points on the printed grid?", "options": ["Plot", "Sketch", "Determine", "State"]}'::jsonb, '{"answer": 0, "explain": "''Plot'' means accurate points on the grid; ''sketch'' shows main features only."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:learn:852a706e', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'learn', 'mcq', 1, '{"readingTitle": "How should you set out working and answers?", "reading": "<p>Marks are earned line by line, so <strong>how</strong> you write matters as much as <em>what</em> you write.</p>\n            <ul>\n              <li><strong>One step per line.</strong> If each step is separate, a slip costs one mark, not all of them.</li>\n              <li><strong>Do not round until the end.</strong> Work to at least <strong>4 significant figures</strong> in the middle, then round the final answer to the demanded precision.</li>\n              <li><strong>Answer to the precision demanded.</strong> \"Give your answer to 1 decimal place\" is enforced by the final mark — too many or too few figures can cost it.</li>\n              <li><strong>Give units</strong> where the quantity has them, and label what the number <em>is</em> (\"speed = 1 km/h\", not just \"1\").</li>\n              <li><strong>Coordinates are pairs.</strong> Write \\( (4,\\ 0) \\), never just \\( x = 4 \\); a stationary point needs both its \\( x \\)- and \\( y \\)-values.</li>\n              <li><strong>An equation answer must be an equation.</strong> Finish \"\\( y = \\tfrac{2}{3}x + 2 \\)\", not just the gradient.</li>\n            </ul>\n            <p>These are the \"cheap marks\" the examiners report being lost every year — none of them require extra maths, only discipline.</p>", "question": "A stationary-point answer gives only the x-value. What happens?", "options": ["It loses the mark — a coordinate must be a pair (x, y)", "Full marks", "It gains a bonus", "It counts as a ''show that''"]}'::jsonb, '{"answer": 0, "explain": "Coordinates must be given as pairs; an x-value with no y-value loses the accuracy mark."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:learn:c06d5f4a', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'learn', 'mcq', 1, '{"readingTitle": "How are marks actually awarded (M, A, B, ft, cao, oe, isw)?", "reading": "<p>OCR schemes award three kinds of mark:</p>\n            <ul>\n              <li><strong>M (method)</strong> — for a correct method <em>applied to the problem</em>. It is not lost for a small numerical slip, but quoting a formula without using it earns nothing.</li>\n              <li><strong>A (accuracy)</strong> — for a correct answer or step, but <strong>only if its method mark is earned</strong>: \"<strong>M0 A1 can never be awarded</strong>\".</li>\n              <li><strong>B</strong> — an <strong>independent</strong> mark for a correct result, regardless of method.</li>\n            </ul>\n            <p>Common abbreviations:</p>\n            <ul>\n              <li><strong>ft</strong> (follow-through) — later marks can still be earned after an earlier error, provided there is no <em>further</em> mistake.</li>\n              <li><strong>cao</strong> — \"correct answer only\": no follow-through or alternatives.</li>\n              <li><strong>oe</strong> — \"or equivalent\": any algebraically equivalent form is accepted.</li>\n              <li><strong>isw</strong> — \"ignore subsequent working\": a correct answer is not spoiled by later fiddling.</li>\n            </ul>\n            <p>Because A marks depend on M marks, <strong>showing your method protects your accuracy marks</strong> — the single most valuable habit on the paper.</p>", "question": "Why can ''M0 A1'' never be awarded?", "options": ["An accuracy mark requires its method mark to be earned first", "A marks are worth 0", "M marks come last", "It is only a typing rule"]}'::jsonb, '{"answer": 0, "explain": "Accuracy (A) marks are conditional on the associated method (M) mark, so M0 A1 is impossible."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:misc:c2bd4599', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Answering an ''exact'' question with \\( x = 1.47 \\) and \\( x = -7.47 \\).</p><p><strong>✅ The correct idea:</strong> ''Exact'' means surd/fraction form. A weak answer rounds to decimals and scores 0; a strong answer gives \\( x = -3 \\pm 2\\sqrt{5} \\) (and may add the decimals as a check).</p>", "question": "Which is an acceptable ''exact'' answer?", "options": ["\\( -3 + 2\\sqrt{5} \\)", "\\( 1.47 \\)", "\\( 1.5 \\)", "about \\( 1.47 \\)"]}'::jsonb, '{"answer": 0, "explain": "Only the surd form is exact; decimals score 0 on an ''exact'' question."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:misc:4a54528b', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In a change-of-sign ''show that'', writing \\( \\text{f}(2) = -1 \\) and \\( \\text{f}(3) = 4 \\) and stopping.</p><p><strong>✅ The correct idea:</strong> The numbers alone earn the method mark but not the answer mark. A strong answer adds: ''there is a change of sign, so a root lies between \\( x = 2 \\) and \\( x = 3 \\).''</p>", "question": "What completes a change-of-sign ''show that''?", "options": ["A sentence stating a root lies in the interval", "A decimal to 3 s.f.", "The quadratic formula", "A second calculator check"]}'::jsonb, '{"answer": 0, "explain": "The concluding statement is the mark most often lost."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:misc:44e68924', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> On a ''detailed reasoning'' factor question, writing the three correct factors straight from the calculator.</p><p><strong>✅ The correct idea:</strong> A calculator-only DR answer scores 0. A strong answer shows \\( \\text{f}(a) = 0 \\) for a trial value, finds the quadratic factor, then states all three factors.</p>", "question": "A DR factorisation with no method shown scores:", "options": ["0", "Full marks", "Half marks", "1 mark"]}'::jsonb, '{"answer": 0, "explain": "DR needs the full analytical method; answer-only scores nothing."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:misc:2ed62086', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Giving a stationary point as ''\\( x = 1 \\)'' with no \\( y \\)-value.</p><p><strong>✅ The correct idea:</strong> Coordinates must be pairs. A weak answer gives only \\( x \\); a strong answer works out \\( y \\) too and writes \\( (1,\\ 8) \\).</p>", "question": "How should a stationary point be stated?", "options": ["As a coordinate pair (x, y)", "As the x-value only", "As the y-value only", "As a gradient"]}'::jsonb, '{"answer": 0, "explain": "A coordinate needs both values; x alone loses the mark."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:misc:72fa703b', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Answering ''r = 1'' when the quantity was a speed with no unit defined.</p><p><strong>✅ The correct idea:</strong> Label what the number is and give its unit. A weak answer writes ''1''; a strong answer writes ''speed = 1 km/h''.</p>", "question": "Why can ''r = 1'' lose a mark?", "options": ["The quantity and unit are not stated", "1 is the wrong number", "It should be exact", "It needs a graph"]}'::jsonb, '{"answer": 0, "explain": "Marks for interpretation require the quantity named and its unit given."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:misc:71c57a32', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A part says ''Hence use your graph to solve...'', but the student solves it on the calculator.</p><p><strong>✅ The correct idea:</strong> ''Hence'' directs you to the method just used. A weak answer ignores it; a strong answer reads the solution from the graph as instructed.</p>", "question": "''Hence use your graph'' means:", "options": ["Read the answer from the graph you drew", "Use the calculator solver", "Start a new algebraic method", "Sketch a second graph"]}'::jsonb, '{"answer": 0, "explain": "''Hence'' ties you to the previous result/method; ignoring it loses marks."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tips:f23d2ff3', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tips', 'mcq', 1, '{"readingTitle": "explain — The ''exact'' ladder", "reading": "<p><strong>0 marks:</strong> \\( x = 1.47,\\ -7.47 \\) only — decimals to an \"exact\" question.</p><p><strong>Partial:</strong> the correct method shown but the answer left as a decimal.</p><p><strong>Full marks:</strong> \\( x = -3 \\pm 2\\sqrt{5} \\). Safest of all: write the exact form <em>and</em> the decimal — the surd earns the marks, the decimal never loses them.</p>", "question": "The safest way to answer an ''exact'' question is to:", "options": ["Give the surd form, optionally with the decimal", "Give only the decimal", "Round to 2 d.p.", "Give the decimal to 3 s.f."]}'::jsonb, '{"answer": 0, "explain": "The exact surd form is required; adding the decimal is harmless."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tips:91b78370', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tips', 'mcq', 1, '{"readingTitle": "tip — The ''show that'' ladder", "reading": "<p><strong>0 marks:</strong> writing the printed result in a box with no working.</p><p><strong>Partial:</strong> full correct working to the numbers, but no concluding sentence.</p><p><strong>Full marks:</strong> every step shown <em>and</em> the concluding statement, e.g. \"change of sign, so a root lies between \\( x = 2 \\) and \\( x = 3 \\).\"</p>", "question": "In a ''show that'', where is the last mark usually lost?", "options": ["The concluding statement", "The first line", "Writing the given answer", "The units"]}'::jsonb, '{"answer": 0, "explain": "Candidates reach the numbers but omit the required concluding sentence."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tips:dc18d6a2', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tips', 'mcq', 1, '{"readingTitle": "explain — The ''detailed reasoning'' ladder", "reading": "<p><strong>0 marks:</strong> the correct answer straight from the calculator on a \"detailed reasoning\" question.</p><p><strong>Partial:</strong> some analytical steps but a key required line missing.</p><p><strong>Full marks:</strong> the complete method — for a factor question, \\( \\text{f}(a) = 0 \\) for a trial value, the quadratic factor, then all three factors.</p>", "question": "On a DR question, a calculator-only correct answer scores:", "options": ["0", "Full marks", "All the method marks", "Half"]}'::jsonb, '{"answer": 0, "explain": "DR requires the analytical method; calculator-only scores nothing."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:tips:638203f4', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'tips', 'mcq', 1, '{"readingTitle": "tip — Protect your marks: method, form, precision", "reading": "<p><strong>0 / partial:</strong> right number, wrong form — a decimal for \"exact\", an \\( x \\)-value with no \\( y \\), a gradient where an equation was asked, or a missing unit.</p><p><strong>Full marks:</strong> one step per line (so a slip costs one mark), work to \\( \\ge 4 \\) s.f. and round only at the end, coordinates as pairs \\( (x,\\ y) \\), units stated, and the answer to the precision demanded.</p>", "question": "Why write one step per line?", "options": ["A slip then costs one mark, not all of them", "It looks neat", "It uses more paper", "It is faster"]}'::jsonb, '{"answer": 0, "explain": "Separated steps preserve method and intermediate marks when a later slip occurs."}'::jsonb),
