('additional-maths:11-1-command-words-and-detailed-reasoning:match:0b4bba77', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “A mark (A1)”?", "options": ["Independent mark for a correct result, regardless of method.", "Mark points accurately on the printed grid and join them.", "Awarded for accuracy, but only if the linked method mark is earned.", "Reach the result with visible justification, not just a bare value."]}'::jsonb, '{"answer": 2, "explain": "“A mark (A1)” means: Awarded for accuracy, but only if the linked method mark is earned."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:match:cbf7ff98', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “B mark (B1)”?", "options": ["Reach the result with visible justification, not just a bare value.", "Independent mark for a correct result, regardless of method.", "Quote the result; no working or method is required.", "Awarded for accuracy, but only if the linked method mark is earned."]}'::jsonb, '{"answer": 1, "explain": "“B mark (B1)” means: Independent mark for a correct result, regardless of method."}'::jsonb),
('additional-maths:11-1-command-words-and-detailed-reasoning:match:8445454e', 'additional-maths', 'additional-maths:11-1-command-words-and-detailed-reasoning', '11.1 Command Words and Detailed Reasoning', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “cao”?", "options": ["Answer in surd, fraction or π form; a decimal alone scores 0.", "Reach the result with visible justification, not just a bare value.", "Correct answer only; no follow-through or alternatives credited.", "Quote the result; no working or method is required."]}'::jsonb, '{"answer": 2, "explain": "“cao” means: Correct answer only; no follow-through or alternatives credited."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:4451c086', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "A question gives a curve, asks for the tangent at a point, then the area it traps. Which areas does it combine?", "options": ["Coordinate geometry, differentiation and integration", "Only integration", "Trigonometry and logarithms", "Only coordinate geometry"]}'::jsonb, '{"answer": 0, "explain": "Finding a point is coordinate geometry, the tangent needs differentiation, and the trapped area needs integration — a classic three-topic synoptic question."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:f29ce924', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "''The line \\( y = 2x + k \\) is a tangent to the circle.'' What technique turns this into an equation for \\( k \\)?", "options": ["Substitute the line into the circle and set the discriminant to 0", "Differentiate the circle", "Integrate the line", "Complete the square on the line"]}'::jsonb, '{"answer": 0, "explain": "A tangent meets the circle once, so the resulting quadratic has one repeated root: discriminant \\( b^2 - 4ac = 0 \\). This links coordinate geometry to the discriminant."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:7e3b8e3c', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "In a multi-part question, part (b) begins ''Hence...''. Your first move should be to:", "options": ["Use your answer from part (a)", "Ignore part (a) and start fresh", "Skip to part (c)", "Convert everything to decimals"]}'::jsonb, '{"answer": 0, "explain": "''Hence'' is an instruction to build on the previous result — the examiner is telling you which method to use."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:5d549b56', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "An unstructured question says ''The cubic has a root \\( x = 2 \\)''. The most useful first line is:", "options": ["\\( \\text{f}(2) = 0 \\)", "\\( \\text{f}''(2) = 0 \\)", "\\( \\int \\text{f}(x)\\,dx = 2 \\)", "\\( \\text{f}(2) = 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "A root means the function is zero there: \\( \\text{f}(2) = 0 \\). Translating the sentence into that equation earns the first mark."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:e43d3800', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "To find the area between two curves that cross at \\( x = 2 \\) and \\( x = 6 \\), you evaluate:", "options": ["\\( \\int_2^6 (\\text{upper} - \\text{lower})\\,dx \\)", "\\( \\int_0^8 (\\text{upper} - \\text{lower})\\,dx \\)", "\\( \\tfrac12\\int_2^6 (\\text{upper} - \\text{lower})\\,dx \\)", "\\( \\int_2^6 \\text{upper}\\,dx \\) only"]}'::jsonb, '{"answer": 0, "explain": "Limits are the intersection points; integrate the difference (upper minus lower). No halving — that is a common error flagged by examiners."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:e2861381', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "A symmetric roof has its apex on the \\( y \\)-axis. The quickest way to find the whole enclosed area is to:", "options": ["Find one half and double it", "Integrate from the far left to the far right in one go always", "Find a quarter and multiply by three", "Guess from the diagram"]}'::jsonb, '{"answer": 0, "explain": "Symmetry about the \\( y \\)-axis means the two halves are equal — compute one half (e.g. \\( x = 0 \\) to \\( 6 \\)) and multiply by 2."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:b62a05bb', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "You have \\( \\frac{dy}{dx} = -2x \\) and want the tangent at \\( (3, 0) \\). The gradient of the tangent is:", "options": ["\\( -6 \\)", "\\( -2x \\)", "\\( 3 \\)", "\\( 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "Substitute \\( x = 3 \\): gradient \\( = -2(3) = -6 \\). The derivative is only the gradient function; you must evaluate it at the point."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:831544ee', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "Which is the safest way to manage a 13-mark question in a 100-mark, 2-hour paper?", "options": ["Spend about 15 minutes, banking method marks part by part", "Spend an hour to get it perfect", "Skip it entirely", "Do only the final part"]}'::jsonb, '{"answer": 0, "explain": "At ≈1.2 min/mark, 13 marks ≈ 15 minutes. Working part by part secures method marks even if you cannot finish."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:1400f29d', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "A candidate finds \\( D \\) has \\( y = 4 \\) and writes the answer as \\( (4, 0) \\). This loses a mark because:", "options": ["The coordinate pair is written the wrong way round / with the wrong values", "\\( y = 4 \\) is wrong", "Decimals are not allowed", "Coordinates should be a single number"]}'::jsonb, '{"answer": 0, "explain": "\\( D \\) is on the \\( y \\)-axis at height 4, so it is \\( (0, 4) \\), not \\( (4, 0) \\). Reading the command word ''coordinates'' carefully avoids this."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:87b91c76', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "An ''exact area'' answer of \\( \\frac{64}{3} \\) is written by a candidate as \\( 21.3 \\). What happens?", "options": ["It may lose the mark if the question demanded an exact form", "It always earns full marks", "It earns more marks for being simpler", "It is never accepted in any question"]}'::jsonb, '{"answer": 0, "explain": "Where a question asks for an exact value, a rounded decimal alone is not exact. If in doubt, give the fraction/surd and the decimal together."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:aca2dea6', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "Which pairing is a genuinely synoptic combination seen in real 6993 papers?", "options": ["Curve sketching + calculus + area between curves", "Only completing the square", "Only reading a value off a calculator", "Only naming a shape"]}'::jsonb, '{"answer": 0, "explain": "OCR June 2019 Q12 combines exactly these: show a maximum, sketch, find intersections, then the area between two curves."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:mcq:fa3d82af', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'mcq', 'mcq', 1, '{"question": "You cannot finish part (b), which found a length. Part (c) needs that length. The best strategy is:", "options": ["Use a sensible assumed value and continue — ft marks are available", "Leave part (c) blank", "Copy part (a)''s answer", "Rub out all your working"]}'::jsonb, '{"answer": 0, "explain": "Mark schemes award follow-through (ft) marks for correct method applied to a wrong earlier value, so always continue."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:ac2a91ad', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "Synoptic questions test brand-new content that is not on the specification."}'::jsonb, '{"answer": false, "explain": "They introduce no new content — the challenge is recognising and combining techniques you already know."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:1be75390', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "Every 6993 paper contains at least one unstructured problem-solving question."}'::jsonb, '{"answer": true, "explain": "The spec guarantees at least one, plus several synoptic questions and 3–4 ''detailed reasoning'' questions."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:2448a6e0', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "''Hence'' means you may ignore the previous part and use any method you like."}'::jsonb, '{"answer": false, "explain": "''Hence'' binds you to use the previous result — it tells you the expected method and saves work."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:d9cc7e49', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "\\( \\frac{dy}{dx} \\) by itself is the equation of the tangent."}'::jsonb, '{"answer": false, "explain": "It is the gradient function; substitute the point''s x-value to get the numerical gradient, then use \\( y - y_1 = m(x - x_1) \\)."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:0f897a9c', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "To find the area between two curves you integrate between their points of intersection."}'::jsonb, '{"answer": true, "explain": "The region is bounded where the curves meet, so the intersection x-values are the limits; integrate upper minus lower."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:ac71c95e', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "On a ''detailed reasoning'' question, a correct calculator answer with no working still earns full marks."}'::jsonb, '{"answer": false, "explain": "Detailed reasoning awards the marks for the visible analytical method; a bare answer scores 0 even when correct."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:41cc880f', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "If you cannot finish an early part, it is always best to leave the rest of the question blank."}'::jsonb, '{"answer": false, "explain": "Use a sensible assumed value and continue — follow-through marks reward correct method on a wrong earlier answer."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tf:e1fe001d', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tf', 'tf', 1, '{"question": "For a figure symmetric about the y-axis, finding one half of the area and doubling is a valid method."}'::jsonb, '{"answer": true, "explain": "Symmetry makes the halves equal, so computing one half and multiplying by 2 is quicker and less error-prone."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:learn:bef71daf', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'learn', 'mcq', 1, '{"readingTitle": "What makes a question ''synoptic'' or ''unstructured''?", "reading": "<p>Every 6993 paper deliberately mixes topics. Two kinds of question test more than fluency:</p>\n            <ul>\n              <li>A <strong>synoptic</strong> question combines <strong>two or more</strong> areas of the specification in one problem — for example coordinate geometry <em>and</em> calculus, or trigonometry <em>and</em> surds. The spec guarantees several of these each year.</li>\n              <li>An <strong>unstructured</strong> (problem-solving) question gives you <strong>little or no scaffolding</strong>: no \"part (a), part (b)\" ladder telling you what to do next. You must choose the strategy yourself. The spec guarantees <strong>at least one</strong> such question every paper.</li>\n            </ul>\n            <p>Neither introduces new content. Everything you need is a technique you have already met — the difficulty is <strong>recognising which techniques</strong> the question is asking for and <strong>joining them together</strong>. These questions carry the AO3 (problem-solving/modelling) marks, worth roughly a fifth of the paper.</p>\n            <p>A typical synoptic closer is a <strong>10–13 mark</strong> \"extended response\" built from a real context — a roof, a boat, a curve and its tangent. The marks are there for method, so a part-finished answer still scores well.</p>", "question": "What is guaranteed on every 6993 paper?", "options": ["At least one unstructured problem-solving question", "A question on brand-new content not in the spec", "A question with no marks for method", "Exactly one synoptic question"]}'::jsonb, '{"answer": 0, "explain": "The spec guarantees at least one unstructured problem-solving question, plus several synoptic ones — all built from techniques you already know."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:learn:6a14b697', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'learn', 'mcq', 1, '{"readingTitle": "How do you break a big multi-part question into steps?", "reading": "<p>Read the <strong>whole</strong> question before writing anything, then work through a fixed routine:</p>\n            <table class=\"worked\">\n              <tr><td>1. <strong>Read to the end.</strong> A later part often reveals what an earlier part is <em>for</em>.</td></tr>\n              <tr><td>2. <strong>Name the topics.</strong> Underline the maths words: \"tangent\", \"area\", \"roots\", \"exact\" — each names a technique.</td></tr>\n              <tr><td>3. <strong>Define variables and sketch.</strong> Put the given information on a diagram or in symbols.</td></tr>\n              <tr><td>4. <strong>Attack part by part.</strong> Each part is usually one technique. Finish it and <strong>keep the result</strong> — the next part likely needs it.</td></tr>\n              <tr><td>5. <strong>Watch for \"Hence\".</strong> \"Hence\" is an instruction to <em>use the previous answer</em>, not to start again.</td></tr>\n              <tr><td>6. <strong>Track exact forms and units</strong> right through — do not round early, and give units where the context has them.</td></tr>\n            </table>\n            <p>Even if you cannot finish part (b), you can usually still attempt part (c) using the <strong>given</strong> or assumed value — the mark scheme awards <strong>follow-through (ft)</strong> marks for correct method on a wrong earlier answer.</p>", "question": "Part (c) says ''Hence find...''. What does ''Hence'' tell you?", "options": ["Use the result from the previous part", "Start again with a fresh method", "Give the answer as a decimal", "Draw a graph to read it off"]}'::jsonb, '{"answer": 0, "explain": "''Hence'' legally binds you to build on the previous result — it saves work and signals which method the examiner expects."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:learn:9a777a52', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'learn', 'mcq', 1, '{"readingTitle": "Worked walkthrough: a curve, a tangent and an area", "reading": "<p>This is how one synoptic question decomposes into three familiar techniques. <em>The curve \\( y = 9 - x^2 \\) meets the positive \\( x \\)-axis at P. Find the tangent to the curve at P, and the area between the curve and the \\( x \\)-axis for \\( 0 \\le x \\le 3 \\).</em></p>\n            <table class=\"worked\">\n              <tr><td><strong>Step 1 — coordinate geometry (find P).</strong> On the \\( x \\)-axis \\( y = 0 \\): \\( 9 - x^2 = 0 \\Rightarrow x = 3 \\) (positive root). So \\( P = (3,\\ 0) \\).</td></tr>\n              <tr><td><strong>Step 2 — differentiation (the tangent).</strong> \\( \\frac{dy}{dx} = -2x \\); at \\( x = 3 \\) the gradient is \\( -6 \\). Tangent: \\( y - 0 = -6(x - 3) \\), i.e. \\[ y = -6x + 18. \\]</td></tr>\n              <tr><td><strong>Step 3 — integration (the area).</strong> \\[ \\int_0^3 (9 - x^2)\\,dx = \\left[\\,9x - \\frac{x^3}{3}\\,\\right]_0^3 = 27 - 9 = 18. \\]</td></tr>\n            </table>\n            <p>Three specification areas — CG, CA (differentiation) and CA (integration) — in one problem, each done on its own then joined. Notice the answer to Step 1 <em>feeds</em> Step 2, exactly as parts of a real exam question chain together.</p>", "question": "In the walkthrough, which value from Step 1 is reused in Step 2?", "options": ["The x-coordinate of P, x = 3", "The area, 18", "The gradient, -6", "The constant +18"]}'::jsonb, '{"answer": 0, "explain": "Step 2 substitutes P''s x-coordinate (3) into dy/dx to get the tangent''s gradient — later parts consume earlier results."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:learn:5d436359', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'learn', 'mcq', 1, '{"readingTitle": "How do you tackle an unstructured question with no scaffold?", "reading": "<p>With no \"(a), (b), (c)\" to guide you, <strong>you</strong> impose the structure:</p>\n            <ul>\n              <li><strong>Translate to maths.</strong> Turn each sentence into an equation, inequality or diagram. \"A root is \\( x = 2 \\)\" means \\( \\text{f}(2) = 0 \\); \"the line is a tangent\" means the discriminant is \\( 0 \\).</li>\n              <li><strong>Decide the goal, then work backwards.</strong> Ask \"what do I need to reach the answer?\" and set up the intermediate steps to get there.</li>\n              <li><strong>Show every analytical step.</strong> Many unstructured questions carry the \"<em>detailed reasoning</em>\" banner — a calculator answer with no working scores <strong>0</strong>, even if it is right.</li>\n              <li><strong>Never leave it blank.</strong> Writing down the correct starting equation earns method marks; a blank earns nothing.</li>\n            </ul>\n            <p><strong>Mini-example.</strong> \"The equation \\( x^3 - 3x + k = 0 \\) has a root \\( x = 2 \\). Find the other roots.\" No scaffold — but \"root \\( x=2 \\)\" gives \\( 8 - 6 + k = 0 \\Rightarrow k = -2 \\); then \\( x^3 - 3x - 2 = (x - 2)(x^2 + 2x + 1) = (x-2)(x+1)^2 \\), so the other root is \\( x = -1 \\) (repeated).</p>", "question": "An unstructured DR question is answered correctly using only a calculator, with no working. What is the score?", "options": ["Zero — detailed reasoning needs the full method shown", "Full marks — the answer is correct", "Half marks", "Full marks if the answer is exact"]}'::jsonb, '{"answer": 0, "explain": "''Detailed reasoning'' awards all the marks for the visible analytical method; a bare calculator answer scores 0 even when correct."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:learn:f34bf855', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'learn', 'mcq', 1, '{"readingTitle": "How do you sanity-check and manage time?", "reading": "<p>The last habits that separate a B from an A on the big questions:</p>\n            <ul>\n              <li><strong>Check against the context.</strong> A length or an area cannot be negative; an angle in a triangle must be under \\( 180^\\circ \\); a probability lies in \\( [0,\\ 1] \\). If your answer breaks the context, you have slipped a sign.</li>\n              <li><strong>Use symmetry.</strong> A symmetric figure (like a roof about its centre line) lets you work one half and <strong>double</strong> — faster and less error-prone.</li>\n              <li><strong>Re-read the command word before you box the answer.</strong> \"Exact\" means surd/fraction, not a decimal; \"coordinates\" means a pair \\( (x,\\ y) \\), not just \\( x \\).</li>\n              <li><strong>Budget time by marks:</strong> roughly \\( 1.2 \\) minutes per mark (\\( 100 \\) marks in \\( 120 \\) minutes). A 13-mark question deserves about \\( 15 \\) minutes — do not sink 30 into it and starve the rest.</li>\n            </ul>\n            <p>If a big question stalls, secure the parts you can, move on, and return with time in hand — a half-finished extended-response question still banks its method marks.</p>", "question": "About how long should you spend on a 13-mark question?", "options": ["Around 15 minutes (≈1.2 min per mark)", "The whole paper", "Exactly 13 minutes then stop", "Under 5 minutes"]}'::jsonb, '{"answer": 0, "explain": "At ≈1.2 minutes per mark (100 marks in 120 minutes), 13 marks is about 15–16 minutes — enough to work carefully without starving the rest."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:learn:eb98cc6f', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'learn', 'mcq', 1, '{"readingTitle": "Which cross-topic mistakes cost the most marks?", "reading": "<p>Examiner reports flag the same synoptic slips year after year:</p>\n            <ul>\n              <li><strong>Missing the \"Hence\" link</strong> — restarting a part from scratch (e.g. reaching for the quadratic formula when the completed-square form is already there), wasting time and risking errors.</li>\n              <li><strong>Confusing the gradient function with the tangent.</strong> \\( \\frac{dy}{dx} \\) is <em>not</em> the equation of the tangent — you must substitute the point''s \\( x \\)-value to get the numerical gradient, then use \\( y - y_1 = m(x - x_1) \\).</li>\n              <li><strong>Wrong limits in area-between-curves.</strong> Integrate between the <strong>intersection points</strong>, subtract \"top minus bottom\", and do <strong>not</strong> divide by 2 unless symmetry genuinely demands it.</li>\n              <li><strong>Forgetting to double (or wrongly doubling)</strong> when a figure is symmetric.</li>\n              <li><strong>Giving up on the unstructured question</strong> — leaving it blank instead of writing the one equation that earns the method mark.</li>\n            </ul>\n            <p>Almost all of these are <em>recognition</em> failures, not arithmetic — which is exactly what these questions are designed to test.</p>", "question": "To find the area between two curves, you integrate between:", "options": ["Their points of intersection, taking top minus bottom", "x = 0 and x = 1 always", "The turning points of each curve", "The y-intercepts"]}'::jsonb, '{"answer": 0, "explain": "The region is bounded by where the curves meet, so the limits are the intersection x-values, and the integrand is the upper curve minus the lower."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:misc:0f38ee2f', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Seeing ''Hence solve'', a candidate restarts with the quadratic formula.</p><p><strong>✅ The correct idea:</strong> ''Hence'' means reuse the previous result. A weak answer restarts and risks fresh errors; a strong answer builds straight on part (a), saving time and marks (a repeated examiner-report complaint).</p>", "question": "''Hence solve f(x) = 0'' after completing the square tells you to:", "options": ["Use your completed-square form", "Use the quadratic formula from scratch", "Factorise by trial", "Sketch the graph"]}'::jsonb, '{"answer": 0, "explain": "''Hence'' directs you to the result you already have — the completed-square form."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:misc:a1fd23a4', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a tangent, a candidate writes the answer as \\( \\frac{dy}{dx} = -2x \\).</p><p><strong>✅ The correct idea:</strong> The derivative is only the gradient function. A strong answer substitutes the point (e.g. \\( x = -6 \\)) to get the numerical gradient, then forms \\( y - y_1 = m(x - x_1) \\). Examiners note many stop at \\( \\frac{dy}{dx} \\).</p>", "question": "After differentiating, the next step for a tangent is to:", "options": ["Substitute the point''s x-value for the gradient", "Integrate the derivative", "Set the derivative equal to y", "Stop — the derivative is the tangent"]}'::jsonb, '{"answer": 0, "explain": "Evaluate \\( \\frac{dy}{dx} \\) at the point to get the gradient, then build the line equation."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:misc:d4d7f8f9', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For an area between two curves, a candidate integrates and then divides the result by 2.</p><p><strong>✅ The correct idea:</strong> Do not halve unless symmetry genuinely requires it. A weak answer divides by 2 out of habit; a strong answer integrates ''upper − lower'' between the intersection points with no extra factor (a specific 2019 examiner-report error).</p>", "question": "When is it correct to double (not halve) an area?", "options": ["When the figure is symmetric and you computed one half", "Always", "Never", "Only for circles"]}'::jsonb, '{"answer": 0, "explain": "Doubling is right when you used symmetry to compute one half; unnecessary halving loses the mark."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:misc:4d8cde24', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A candidate integrates a symmetric roof area from \\( -6 \\) to \\( 6 \\) but forgets the tangent line is only valid on one half.</p><p><strong>✅ The correct idea:</strong> Each tangent line only describes its own half of the roof. A strong answer integrates one half (e.g. \\( 0 \\) to \\( 6 \\)) with the correct line and doubles, or uses each tangent on its own side — flagged in the 2024 report as a cause of ''unreasonably large answers''.</p>", "question": "Why can''t you use one tangent''s equation across the whole symmetric roof?", "options": ["Each tangent is only valid on its own half", "Tangents have no equation", "The roof is not symmetric", "You must always integrate 0 to 12"]}'::jsonb, '{"answer": 0, "explain": "AD and BD are different lines; each is only valid on its side, so integrate one half and double."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:misc:a299020f', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Facing an unstructured question with no parts, a candidate leaves it blank.</p><p><strong>✅ The correct idea:</strong> Impose your own structure. A weak response gives up; a strong response translates the first sentence into an equation (e.g. \\( \\text{f}(2) = 0 \\)) — that alone often earns the first method mark.</p>", "question": "The best response to a hard unstructured question is to:", "options": ["Write the starting equation and attempt a method", "Leave it blank", "Only write the final answer", "Copy an earlier question"]}'::jsonb, '{"answer": 0, "explain": "Even the correct opening equation banks method marks; a blank scores nothing."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:misc:786e6c1c', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A candidate finds a coordinate''s height \\( y = 4 \\) and writes the point as \\( (4, 0) \\).</p><p><strong>✅ The correct idea:</strong> Read the command word ''coordinates''. A strong answer gives the pair in the right order — a point on the y-axis at height 4 is \\( (0, 4) \\). The 2024 report noted candidates who found \\( y = 4 \\) but mis-stated the pair.</p>", "question": "A point on the y-axis at height 4 has coordinates:", "options": ["\\( (0, 4) \\)", "\\( (4, 0) \\)", "\\( 4 \\)", "\\( (4, 4) \\)"]}'::jsonb, '{"answer": 0, "explain": "On the y-axis \\( x = 0 \\), so the point is \\( (0, 4) \\)."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tips:1d322a8d', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tips', 'mcq', 1, '{"readingTitle": "explain — The decompose-a-big-question ladder", "reading": "<p><strong>0 marks:</strong> stare at a 13-mark roof question, see \"roof\" and \"area\", panic, write nothing.</p>\n        <p><strong>Partial:</strong> find the points A, B, C (coordinate geometry), then stop — still banks the opening marks.</p>\n        <p><strong>Full marks:</strong> name each topic, do the parts in order — points → tangent → apex → area — reusing each result in the next, using symmetry, and checking the area is positive. Each technique is one you already know; the skill is joining them.</p>", "question": "The key skill in a synoptic question is:", "options": ["Recognising and joining techniques you already know", "Learning new content on the spot", "Working faster than everyone else", "Avoiding all diagrams"]}'::jsonb, '{"answer": 0, "explain": "No new content appears; you identify which known techniques the question spans and chain them together."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tips:99852377', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tips', 'mcq', 1, '{"readingTitle": "tip — Make ''Hence'' and follow-through work for you", "reading": "<p>When a part says \"<em>Hence</em>\", reach for your previous answer, not a fresh method — restarting wastes minutes and invites errors. And if an early part defeats you, carry a sensible value forward: examiners award <strong>follow-through</strong> marks for correct method on a wrong number, so a stuck part need not sink the whole question.</p>", "question": "You got part (a) wrong but part (b) needs it. You should:", "options": ["Carry a value forward and keep going for ft marks", "Give up on part (b)", "Guess the final answer only", "Erase part (a)"]}'::jsonb, '{"answer": 0, "explain": "Follow-through marks reward correct method on a wrong earlier answer, so always continue."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:tips:7aa4e806', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'tips', 'mcq', 1, '{"readingTitle": "explain — Command words and checks that save marks", "reading": "<p>Before boxing an answer, re-read the command word. <strong>\"Exact\"</strong> → leave the surd/fraction (\\( \\frac{64}{3} \\), not \\( 21.3 \\)); <strong>\"coordinates\"</strong> → a pair \\( (x,\\ y) \\) in the right order; a length or area → must be <strong>positive</strong>; a context with metres → give <strong>units</strong>. These are free marks that tired candidates throw away.</p>", "question": "A question asks for an exact area. Which answer is safest?", "options": ["\\( \\frac{64}{3} \\) (optionally with the decimal)", "\\( 21.3 \\) only", "\\( 21 \\) only", "about 21"]}'::jsonb, '{"answer": 0, "explain": "''Exact'' needs the fraction or surd; adding the decimal is harmless but the exact form earns the mark."}'::jsonb),
('additional-maths:11-2-synoptic-and-unstructured-problems:fib:91beb420', 'additional-maths', 'additional-maths:11-2-synoptic-and-unstructured-problems', '11.2 Synoptic and Unstructured Problems', 'fib', 'fib', 1, '{"question": "A question that combines two or more areas of the specification is described as ___B1___.", "blankOptions": {"B1": ["double", "follow-through", "synoptic", "substitute"]}}'::jsonb, '{"blanks": {"B1": "synoptic"}}'::jsonb)
